_LANG = "en"

def set_language(lang):
    global _LANG
    if lang in TRANSLATIONS:
        _LANG = lang

def t(key, **kwargs):
    table = TRANSLATIONS.get(_LANG, {})
    text = table.get(key)
    if text is None:
        text = TRANSLATIONS.get("en", {}).get(key, key)
    if kwargs:
        try:
            text = text.format(**kwargs)
        except Exception:
            pass
    return text

